import json
import os
import logging
import psycopg2
import psycopg2.extras

logger = logging.getLogger()
logger.setLevel(logging.INFO)

DB_HOST = os.environ.get('DB_HOST', '')
DB_PORT = int(os.environ.get('DB_PORT', '5432'))
DB_NAME = os.environ.get('DB_NAME', '')
DB_USER = os.environ.get('DB_USER', '')
DB_PASSWORD = os.environ.get('DB_PASSWORD', '')

ALLOWED_TABLES = frozenset({
    'users',
    'orders',
    'products',
    'categories',
    'inventory',
})

MAX_LIMIT = 1000
DEFAULT_LIMIT = 100


def get_connection():
    conn = psycopg2.connect(
        host=DB_HOST,
        port=DB_PORT,
        dbname=DB_NAME,
        user=DB_USER,
        password=DB_PASSWORD,
        connect_timeout=5,
        sslmode='require',
    )
    conn.set_session(readonly=True, autocommit=True)
    return conn


_connection = None


def get_cached_connection():
    global _connection
    if _connection is None or _connection.closed:
        _connection = get_connection()
    else:
        try:
            with _connection.cursor() as cur:
                cur.execute('SELECT 1')
        except (psycopg2.OperationalError, psycopg2.InterfaceError):
            logger.info('Reconnecting to database due to stale connection')
            try:
                _connection.close()
            except Exception:
                pass
            _connection = get_connection()
    return _connection


def validate_table_name(table_name):
    if not table_name:
        raise ValueError('Table name is required')
    if table_name not in ALLOWED_TABLES:
        raise ValueError(f'Table "{table_name}" is not in the allowed list: {sorted(ALLOWED_TABLES)}')
    return table_name


def validate_limit(limit_value):
    try:
        limit = int(limit_value)
    except (TypeError, ValueError):
        return DEFAULT_LIMIT
    if limit < 1:
        return 1
    if limit > MAX_LIMIT:
        return MAX_LIMIT
    return limit


def validate_offset(offset_value):
    try:
        offset = int(offset_value)
    except (TypeError, ValueError):
        return 0
    if offset < 0:
        return 0
    return offset


def build_response(status_code, body):
    return {
        'statusCode': status_code,
        'headers': {
            'Content-Type': 'application/json',
            'X-Content-Type-Options': 'nosniff',
        },
        'body': json.dumps(body, default=str),
    }


def lambda_handler(event, context):
    try:
        params = event.get('queryStringParameters') or {}
        body_params = {}
        if event.get('body'):
            try:
                body_params = json.loads(event['body'])
            except (json.JSONDecodeError, TypeError):
                return build_response(400, {'error': 'Invalid JSON body'})

        table = params.get('table') or body_params.get('table')
        limit = params.get('limit') or body_params.get('limit', DEFAULT_LIMIT)
        offset = params.get('offset') or body_params.get('offset', 0)
        filters = body_params.get('filters', {})

        try:
            table = validate_table_name(table)
        except ValueError as e:
            return build_response(400, {'error': str(e)})

        limit = validate_limit(limit)
        offset = validate_offset(offset)

        conn = get_cached_connection()

        allowed_filter_columns = {
            'users': frozenset({'id', 'email', 'status', 'created_at'}),
            'orders': frozenset({'id', 'user_id', 'status', 'created_at'}),
            'products': frozenset({'id', 'category_id', 'name', 'status'}),
            'categories': frozenset({'id', 'name'}),
            'inventory': frozenset({'id', 'product_id', 'warehouse_id'}),
        }

        where_clauses = []
        param_values = []
        table_allowed_cols = allowed_filter_columns.get(table, frozenset())

        if isinstance(filters, dict):
            for col, val in filters.items():
                if col not in table_allowed_cols:
                    return build_response(400, {
                        'error': f'Filter column "{col}" is not allowed for table "{table}"'
                    })
                where_clauses.append(
                    psycopg2.sql.SQL('{} = %s').format(psycopg2.sql.Identifier(col))
                )
                param_values.append(val)

        import psycopg2.sql as sql

        query = sql.SQL('SELECT * FROM {table}').format(
            table=sql.Identifier(table)
        )

        if where_clauses:
            query = query + sql.SQL(' WHERE ') + sql.SQL(' AND ').join(where_clauses)

        query = query + sql.SQL(' ORDER BY id LIMIT %s OFFSET %s')
        param_values.extend([limit, offset])

        count_query = sql.SQL('SELECT COUNT(*) FROM {table}').format(
            table=sql.Identifier(table)
        )
        if where_clauses:
            count_query = count_query + sql.SQL(' WHERE ') + sql.SQL(' AND ').join(where_clauses)

        with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
            count_params = param_values[:-2] if param_values else []
            cur.execute(count_query, count_params if count_params else None)
            total_count = cur.fetchone()['count']

            cur.execute(query, param_values)
            rows = cur.fetchall()

        result = {
            'table': table,
            'total_count': total_count,
            'limit': limit,
            'offset': offset,
            'count': len(rows),
            'data': rows,
        }

        logger.info(
            'Query executed successfully: table=%s, filters=%d, results=%d, total=%d',
            table, len(where_clauses), len(rows), total_count
        )

        return build_response(200, result)

    except psycopg2.OperationalError as e:
        logger.error('Database connection error: %s', str(e))
        return build_response(503, {'error': 'Database connection unavailable'})

    except psycopg2.Error as e:
        logger.error('Database error: %s', str(e))
        return build_response(500, {'error': 'Database query failed'})

    except Exception as e:
        logger.error('Unexpected error: %s', str(e), exc_info=True)
        return build_response(500, {'error': 'Internal server error'})